def set_permissions(vhost, username):
    url = f"{rabbitmq_host}/api/permissions/{vhost}/{username}"
    data = {"configure": ".*", "write": ".*", "read": ".*"}
    response = requests.put(url, json=data, auth=HTTPBasicAuth(admin_user, admin_password))
    response.raise_for_status()

def setup_application(app):
    create_vhost(app['vhost'])
